+
+    #[test]
+    fn multiple_types() {
+        let mut heap = RegionHeap::new();
+
+        let idx1 = heap.alloc(42u32);
+        let idx2 = heap.alloc("hello".to_string());
+        let idx3 = heap.alloc(vec![1, 2, 3]);
+
+        assert_eq!(heap.get::<u32>(idx1), Some(&42));
